ALTER TABLE regulations ADD COLUMN IF NOT EXISTS notification_requirements_text character varying (255) DEFAULT NULL;
CREATE TYPE CadenceType as ENUM ('None', 'Quarterly', 'B_Annual', 'Annual', 'Every2years');
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS pen_test_cadence CadenceType DEFAULT 'None';
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS vulnerability_scan_cadence CadenceType DEFAULT 'None';
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS policies_and_procedures_review CadenceType DEFAULT 'None';
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS risk_impact_assessments CadenceType DEFAULT 'None';
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS details_of_vendor_program character varying (255) DEFAULT NULL;
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS vendor_due_diligence_requirements character varying (255) DEFAULT NULL;
ALTER TABLE regulations ADD COLUMN IF NOT EXISTS mfa boolean DEFAULT FALSE;

CREATE TABLE IF NOT EXISTS regulation_ages
(
	id serial,
	regulation_id integer DEFAULT NULL,
	age integer DEFAULT NULL,
	comments text DEFAULT NULL,

	CONSTRAINT pk_regulation_ages PRIMARY KEY (id)
	, CONSTRAINT fk_regulation_ages FOREIGN KEY (regulation_id) REFERENCES regulations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX IF NOT EXISTS i_regulation_ages ON regulation_ages (regulation_id);

